const HUB = 'https://hub.snapshot.org/graphql';
const RELAY = 'https://seq.snapshot.org/';

// 1. Fetch active proposal
const proposal = await fetch(HUB, {
  method: 'POST', headers: { 'content-type': 'application/json' },
  body: JSON.stringify({ query: `{ proposal(id: "${id}") { id space { id } choices snapshot end } }` })
}).then(r => r.json()).then(r => r.data.proposal);

if (proposal.end * 1000 < Date.now()) throw new Error('Proposal closed');

// 2. Sign Vote typed data
const signature = await wallet.signTypedData({
  domain: { name: 'snapshot', version: '0.1.4' },
  types: { Vote: [/* fields */] },
  primaryType: 'Vote',
  message: { from: agent, space: proposal.space.id, timestamp: BigInt(Math.floor(Date.now()/1000)),
             proposal: proposal.id, choice, reason, app: 'skillai', metadata: '{}' }
});

// 3. Submit envelope
const receipt = await fetch(RELAY, {
  method: 'POST', headers: { 'content-type': 'application/json' },
  body: JSON.stringify({ address: agent, sig: signature, data: { domain: ..., types: ..., message: ... } })
}).then(r => r.json());
console.log('vote id', receipt.id);
